files="abcdefgh"
def diag_moves(sq, board):
    f=files.index(sq[0]); r=int(sq[1])-1; moves=[]
    for df,dr in [(1,1),(1,-1),(-1,1),(-1,-1)]:
        nf,nr=f+df,r+dr
        while 0<=nf<8 and 0<=nr<8:
            t=files[nf]+str(nr+1)
            if t in board: moves.append((t,'occ:'+board[t])); break
            moves.append((t,'empty')); nf+=df; nr+=dr
    return moves
def fen_from(board, side='w'):
    rows=[]
    for r in range(8,0,-1):
        row=''; e=0
        for f in 'abcdefgh':
            sq=f+str(r)
            if sq in board:
                if e: row+=str(e); e=0
                row+=board[sq]
            else: e+=1
        if e: row+=str(e)
        rows.append(row)
    return '/'.join(rows)+f' {side} - - 0 1'

# Black bishop a1 (light square? a1 is dark). bishop a1 dark-sq. Only diagonal a1-h8: b2,c3...
# Trap: white pawn b2 blocks immediately. Then bishop a1 has ZERO moves. White Kb1? a1 adjacent
# to b1/b2/a2. Need a piece to capture a1. A knight attacking a1: Nb3 attacks a1? Nc2 attacks a1.
def knight_attacks(sq):
    f=files.index(sq[0]); r=int(sq[1])-1; res=[]
    for d in [(1,2),(2,1),(-1,2),(-2,1),(1,-2),(2,-1),(-1,-2),(-2,-1)]:
        nf,nr=f+d[0],r+d[1]
        if 0<=nf<8 and 0<=nr<8: res.append(files[nf]+str(nr+1))
    return res
print("Nb3 attacks a1?", 'a1' in knight_attacks('b3'))
print("Nc2 attacks a1?", 'a1' in knight_attacks('c2'))
b={'a1':'b','b2':'P','c2':'N','h8':'k','a8':'K'}
